                    "id": "content-tree-decision-making-optimization-stochastic-optimization-minimal-variance-sampling-in-stochastic-gradient-boosting-papers-1910-13204-md",
                    "label": "Minimal Variance Sampling in Stochastic Gradient Boosting",
                    "kind": "paper",
