                            "paper": {
                              "id": "2506_13753",
                              "title": "Edge Nearest Neighbor: Neighbor-Finding Revisited in Sampling-Based Motion Planning",
                              "authors": [
                                "Stav Ashur",
                                "Nancy M. Amato",
                                "Sariel Har-Peled"
                              ],
                              "year": 2025,
                              "abstract": "Neighborhood finders and nearest neighbor queries are fundamental parts of sampling based motion planning algorithms. Using different distance metrics or otherwise changing the definition of a neighborhood produces different algorithms with unique empiric and theoretical properties. LaValle suggests a neighborhood finder for the Rapidly-exploring Random Tree RRT algorithm which finds the nearest neighbor of the sampled point on the swath of the tree, that is on the set of all of the points on the tree edges, using a hierarchical data structure. In this paper we implement such a neighborhood finder and show, theoretically and experimentally, that this results in more efficient algorithms, and suggest a variant of the Rapidly-exploring Random Graph RRG algorithm that better exploits the exploration properties of the newly described subroutine for finding narrow passages.",
                              "mindMapUrl": "../mind-map/#paper=2506_13753"
                            }
