                            "id": "content-tree-decision-making-motion-planning-path-planning-path-optimization-path-smoothing-smooth-feedback-motion-planning-with-reduced-curvature-papers-2604-01614-md",
                            "label": "Smooth Feedback Motion Planning with Reduced Curvature",
                            "kind": "paper",
                            "source": "papers/2604_01614.md",
