                        "id": "content-tree-decision-making-motion-planning-trajectory-planning-trajectory-generation-dynamic-movement-primitives-in-robotics-a-tutorial-survey-papers-2102-03861-md",
                        "label": "Dynamic Movement Primitives in Robotics: A Tutorial Survey",
