                            "paper": {
                              "id": "2025_xia_an_adaptive_projection_differential",
                              "title": "An Adaptive Projection Differential Dynamic Programming Method for Control Constrained Trajectory Optimization",
                              "authors": [
                                "Zhehao Xia",
                                "Yizhong Wu"
                              ],
                              "year": 2025,
                              "abstract": "To address the issue of missing constraints on control variables in the trajectory optimization problem of the differential dynamic programming (DDP) method, the adaptive projection differential dynamic programming (AP-DDP) method is proposed. The core of the AP-DDP method is to introduce adaptive relaxation coefficients to dynamically adjust the smoothness of the projection function and to effectively solve the gradient disappearance problem that may occur when the control variable is close to the constraint boundary. Additionally, the iterative strategy of the relaxation coefficient accelerates the search for a feasible solution in the initial stage, thereby improving the algorithm’s efficiency. When applied to three trajectory optimization problems, compared with similar truncated DDP, projected DDP, and Box-DDP methods, the AP-DDP method found the optimal solution in the shortest computation time, thereby proving the efficiency of the proposed algorithm. While ensuring the iterative process reaches the global optimum, the computing time of the AP-DDP method was reduced by 32.8%, 13.3%, and 18.5%, respectively, in the three examples.",
                              "mindMapUrl": "../mind-map/#paper=2025_xia_an_adaptive_projection_differential"
                            }
