                            "id": "content-tree-decision-making-motion-planning-trajectory-planning-trajectory-optimization-nonlinear-optimization-admm-based-continuous-trajectory-optimization-in-graphs-of-convex-sets-papers-2603-11335-md",
                            "label": "ADMM-based Continuous Trajectory Optimization in Graphs of Convex Sets",
