                    "id": "content-tree-decision-making-control-robust-control-policy-optimization-of-mixed-h2-h-infinity-control-benign-nonconvexity-and-global-optimality-papers-2603-04843-md",
                    "label": "Policy Optimization of Mixed H2/H-infinity Control: Benign Nonconvexity and Global Optimality",
                    "kind": "paper",
