                    "id": "content-tree-decision-making-reinforcement-learning-imitation-learning-sample-efficient-expert-query-control-in-active-imitation-learning-via-conformal-prediction-papers-2512-00453-md",
                    "label": "Sample-Efficient Expert Query Control in Active Imitation Learning via Conformal Prediction",
                    "kind": "paper",
