                        "id": "content-tree-decision-making-reinforcement-learning-policy-optimization-rl-for-linear-systems-lqr-through-the-lens-of-first-order-methods-papers-1907-08921-md",
                        "label": "LQR through the Lens of First Order Methods",
                        "kind": "paper",
                        "source": "papers/1907_08921.md",
