                        "id": "content-tree-decision-making-reinforcement-learning-policy-optimization-rl-for-linear-systems-convergence-of-flow-policy-gradient-learning-for-linear-quadratic-regulator-problems-papers-2511-11131-md",
                        "label": "Convergence of Flow-Policy Gradient Learning for Linear Quadratic Regulator Problems",
