                        "id": "content-tree-decision-making-reinforcement-learning-model-based-rl-adaptive-control-probabilistic-robustness-in-the-gap-metric-papers-2507-10010-md",
                        "label": "Probabilistic Robustness in the Gap Metric",
                        "kind": "paper",
