                        "id": "content-tree-decision-making-reinforcement-learning-model-based-rl-adaptive-control-reinforcement-learning-and-control-as-probabilistic-inference-tutorial-and-review-papers-1805-00909-md",
                        "label": "Reinforcement Learning and Control as Probabilistic Inference: Tutorial and Review",
                        "kind": "paper",
