                        "id": "content-tree-decision-making-reinforcement-learning-model-based-rl-adaptive-control-soft-mpcritic-amortized-model-predictive-value-iteration-papers-2604-01477-md",
                        "label": "Soft MPCritic: Amortized Model Predictive Value Iteration",
                        "kind": "paper",
                        "source": "papers/2604_01477.md",
