                        "id": "content-tree-decision-making-reinforcement-learning-model-based-rl-adaptive-control-soft-projections-for-robust-data-driven-control-papers-2604-00900-md",
                        "label": "Soft projections for robust data-driven control",
                        "kind": "paper",
