                        "id": "content-tree-decision-making-reinforcement-learning-model-based-rl-adaptive-control-stochastic-data-driven-predictive-control-regularization-estimation-and-constraint-tightening-papers-2312-02758-md",
                        "label": "Stochastic Data-Driven Predictive Control: Regularization, Estimation, and Constraint Tightening",
                        "kind": "paper",
