                    "id": "content-tree-prediction-motion-prediction-prediction-horizon-prediction-horizon-requirements-for-automated-driving-papers-2402-03893-md",
                    "label": "Prediction Horizon Requirements for Automated Driving",
                    "kind": "paper",
                    "source": "papers/2402_03893.md",
