                        "id": "content-tree-prediction-machine-learning-time-series-algorithms-informer-papers-2012-07436-md",
                        "label": "Informer",
                        "kind": "paper",
                        "source": "papers/2012_07436.md",
                        "url": "../papers/2012_07436/",
