                    "label": "Visual Sensitivities to Color Differences in Daylight",
                    "kind": "paper",
                    "source": "papers/1942_macadam_visual_sensitivities_to_color_differences.md",
                    "url": "../papers/1942_macadam_visual_sensitivities_to_color_differences/",
